import React, { useState } from 'react';
import { useUsers } from '../../context/UserContext';

function AddUserForm({ onClose, onSuccess }) {
  const { addUser } = useUsers();
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    role: '',
    name: '',
    email: '',
    age: '',
    gender: '',
    subject: ''
  });
  const [errors, setErrors] = useState({});

  const subjects = [
    'Mathematics', 'Physics', 'Chemistry', 'Biology', 
    'English', 'Computer Science', 'History', 'Geography',
    'Economics', 'Physical Education', 'Art', 'Music',
    'Administration', 'Student Affairs', 'Finance'
  ];

  const validateStep1 = () => {
    const newErrors = {};
    if (!formData.role) newErrors.role = 'Please select a role';
    if (!formData.name) newErrors.name = 'Name is required';
    if (!formData.email) newErrors.email = 'Email is required';
    else if (!/\S+@\S+\.\S+/.test(formData.email)) newErrors.email = 'Email is invalid';
    return newErrors;
  };

  const validateStep2 = () => {
    const newErrors = {};
    if (!formData.age) newErrors.age = 'Age is required';
    else if (formData.age < 21 || formData.age > 70) newErrors.age = 'Age must be between 21 and 70';
    if (!formData.gender) newErrors.gender = 'Please select gender';
    if (!formData.subject) newErrors.subject = 'Please select subject';
    return newErrors;
  };

  const handleNext = () => {
    if (step === 1) {
      const stepErrors = validateStep1();
      if (Object.keys(stepErrors).length === 0) {
        setStep(2);
        setErrors({});
      } else {
        setErrors(stepErrors);
      }
    }
  };

  const handleBack = () => {
    setStep(1);
    setErrors({});
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    if (step === 2) {
      const stepErrors = validateStep2();
      if (Object.keys(stepErrors).length === 0) {
        addUser(formData);
        onSuccess();
      } else {
        setErrors(stepErrors);
      }
    }
  };

  return (
    <div style={{
      position: 'fixed',
      top: 0,
      left: 0,
      right: 0,
      bottom: 0,
      backgroundColor: 'rgba(0,0,0,0.5)',
      display: 'flex',
      justifyContent: 'center',
      alignItems: 'center',
      zIndex: 1000,
      backdropFilter: 'blur(5px)'
    }}>
      <div style={{
        background: 'white',
        borderRadius: '20px',
        width: '500px',
        maxWidth: '90%',
        boxShadow: '0 20px 40px rgba(0,0,0,0.3)',
        overflow: 'hidden'
      }}>
        {/* Header with gradient */}
        <div style={{
          background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
          padding: '30px',
          textAlign: 'center',
          position: 'relative'
        }}>
          <div style={{
            position: 'absolute',
            top: '10px',
            right: '10px',
            cursor: 'pointer',
            color: 'white',
            fontSize: '24px'
          }} onClick={onClose}>✕</div>
          <div style={{
            width: '80px',
            height: '80px',
            background: 'white',
            borderRadius: '50%',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            margin: '0 auto 15px',
            fontSize: '40px'
          }}>
            {step === 1 ? '👤' : '📚'}
          </div>
          <h3 style={{ color: 'white', margin: 0, fontSize: '24px' }}>
            {step === 1 ? 'Select User Role' : 'Complete Profile'}
          </h3>
          <p style={{ color: 'rgba(255,255,255,0.8)', margin: '5px 0 0' }}>
            Step {step} of 2
          </p>
        </div>

        {/* Progress Bar */}
        <div style={{
          height: '4px',
          background: '#f0f0f0',
          width: '100%'
        }}>
          <div style={{
            height: '100%',
            width: step === 1 ? '50%' : '100%',
            background: 'linear-gradient(90deg, #667eea, #764ba2)',
            transition: 'width 0.3s'
          }}></div>
        </div>

        <form onSubmit={handleSubmit}>
          <div style={{ padding: '30px' }}>
            {step === 1 ? (
              // Step 1: Role Selection
              <div>
                <div style={{ marginBottom: '25px' }}>
                  <label style={{ 
                    display: 'block', 
                    marginBottom: '10px',
                    fontWeight: 'bold',
                    color: '#333'
                  }}>
                    Select User Role *
                  </label>
                  <div style={{
                    display: 'grid',
                    gridTemplateColumns: '1fr 1fr',
                    gap: '15px'
                  }}>
                    {/* Admin Button */}
                    <div
                      onClick={() => setFormData({...formData, role: 'admin'})}
                      style={{
                        padding: '25px 15px',
                        borderRadius: '15px',
                        border: formData.role === 'admin' ? '3px solid #667eea' : '2px solid #e0e0e0',
                        background: formData.role === 'admin' ? 'linear-gradient(135deg, #f093fb20, #f5576c20)' : 'white',
                        cursor: 'pointer',
                        textAlign: 'center',
                        transition: 'all 0.3s',
                        boxShadow: formData.role === 'admin' ? '0 10px 20px rgba(102,126,234,0.2)' : 'none'
                      }}
                    >
                      <div style={{ fontSize: '40px', marginBottom: '10px' }}>👑</div>
                      <h4 style={{ margin: '0 0 5px', color: '#333' }}>Admin</h4>
                      <p style={{ margin: '0', fontSize: '12px', color: '#666' }}>
                        Full system access
                      </p>
                    </div>

                    {/* Teacher Button */}
                    <div
                      onClick={() => setFormData({...formData, role: 'teacher'})}
                      style={{
                        padding: '25px 15px',
                        borderRadius: '15px',
                        border: formData.role === 'teacher' ? '3px solid #4facfe' : '2px solid #e0e0e0',
                        background: formData.role === 'teacher' ? 'linear-gradient(135deg, #4facfe20, #00f2fe20)' : 'white',
                        cursor: 'pointer',
                        textAlign: 'center',
                        transition: 'all 0.3s',
                        boxShadow: formData.role === 'teacher' ? '0 10px 20px rgba(79,172,254,0.2)' : 'none'
                      }}
                    >
                      <div style={{ fontSize: '40px', marginBottom: '10px' }}>👩🏫</div>
                      <h4 style={{ margin: '0 0 5px', color: '#333' }}>Teacher</h4>
                      <p style={{ margin: '0', fontSize: '12px', color: '#666' }}>
                        Faculty access
                      </p>
                    </div>
                  </div>
                  {errors.role && (
                    <p style={{ color: '#f44336', fontSize: '12px', marginTop: '5px' }}>
                      {errors.role}
                    </p>
                  )}
                </div>

                <div style={{ marginBottom: '20px' }}>
                  <label style={{ 
                    display: 'block', 
                    marginBottom: '5px',
                    fontWeight: 'bold',
                    color: '#333'
                  }}>
                    Full Name *
                  </label>
                  <input
                    type="text"
                    value={formData.name}
                    onChange={(e) => setFormData({...formData, name: e.target.value})}
                    placeholder="Enter full name"
                    style={{
                      width: '100%',
                      padding: '12px 15px',
                      borderRadius: '8px',
                      border: errors.name ? '2px solid #f44336' : '2px solid #e0e0e0',
                      fontSize: '14px',
                      transition: 'border 0.3s'
                    }}
                  />
                  {errors.name && (
                    <p style={{ color: '#f44336', fontSize: '12px', marginTop: '5px' }}>
                      {errors.name}
                    </p>
                  )}
                </div>

                <div style={{ marginBottom: '20px' }}>
                  <label style={{ 
                    display: 'block', 
                    marginBottom: '5px',
                    fontWeight: 'bold',
                    color: '#333'
                  }}>
                    Email Address *
                  </label>
                  <input
                    type="email"
                    value={formData.email}
                    onChange={(e) => setFormData({...formData, email: e.target.value})}
                    placeholder="Enter email address"
                    style={{
                      width: '100%',
                      padding: '12px 15px',
                      borderRadius: '8px',
                      border: errors.email ? '2px solid #f44336' : '2px solid #e0e0e0',
                      fontSize: '14px'
                    }}
                  />
                  {errors.email && (
                    <p style={{ color: '#f44336', fontSize: '12px', marginTop: '5px' }}>
                      {errors.email}
                    </p>
                  )}
                </div>
              </div>
            ) : (
              // Step 2: Personal Details
              <div>
                <div style={{ 
                  background: '#f8f9fa',
                  padding: '15px',
                  borderRadius: '10px',
                  marginBottom: '20px',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '10px'
                }}>
                  <span style={{
                    padding: '5px 10px',
                    background: formData.role === 'admin' ? '#f093fb' : '#4facfe',
                    color: 'white',
                    borderRadius: '5px',
                    fontSize: '12px'
                  }}>
                    {formData.role === 'admin' ? '👑 Admin' : '👩🏫 Teacher'}
                  </span>
                  <span style={{ color: '#666' }}>{formData.name}</span>
                  <span style={{ color: '#666', marginLeft: 'auto' }}>{formData.email}</span>
                </div>

                <div style={{ marginBottom: '20px' }}>
                  <label style={{ 
                    display: 'block', 
                    marginBottom: '5px',
                    fontWeight: 'bold',
                    color: '#333'
                  }}>
                    Age *
                  </label>
                  <input
                    type="number"
                    value={formData.age}
                    onChange={(e) => setFormData({...formData, age: parseInt(e.target.value)})}
                    placeholder="Enter age"
                    min="21"
                    max="70"
                    style={{
                      width: '100%',
                      padding: '12px 15px',
                      borderRadius: '8px',
                      border: errors.age ? '2px solid #f44336' : '2px solid #e0e0e0',
                      fontSize: '14px'
                    }}
                  />
                  {errors.age && (
                    <p style={{ color: '#f44336', fontSize: '12px', marginTop: '5px' }}>
                      {errors.age}
                    </p>
                  )}
                </div>

                <div style={{ marginBottom: '20px' }}>
                  <label style={{ 
                    display: 'block', 
                    marginBottom: '5px',
                    fontWeight: 'bold',
                    color: '#333'
                  }}>
                    Gender *
                  </label>
                  <div style={{ display: 'flex', gap: '15px' }}>
                    {['Male', 'Female', 'Other'].map(g => (
                      <label key={g} style={{ display: 'flex', alignItems: 'center', gap: '5px' }}>
                        <input
                          type="radio"
                          name="gender"
                          value={g}
                          checked={formData.gender === g}
                          onChange={(e) => setFormData({...formData, gender: e.target.value})}
                        />
                        <span>{g === 'Male' ? '👨' : g === 'Female' ? '👩' : '🧑'} {g}</span>
                      </label>
                    ))}
                  </div>
                  {errors.gender && (
                    <p style={{ color: '#f44336', fontSize: '12px', marginTop: '5px' }}>
                      {errors.gender}
                    </p>
                  )}
                </div>

                <div style={{ marginBottom: '20px' }}>
                  <label style={{ 
                    display: 'block', 
                    marginBottom: '5px',
                    fontWeight: 'bold',
                    color: '#333'
                  }}>
                    Subject Specialization *
                  </label>
                  <select
                    value={formData.subject}
                    onChange={(e) => setFormData({...formData, subject: e.target.value})}
                    style={{
                      width: '100%',
                      padding: '12px 15px',
                      borderRadius: '8px',
                      border: errors.subject ? '2px solid #f44336' : '2px solid #e0e0e0',
                      fontSize: '14px'
                    }}
                  >
                    <option value="">Select a subject</option>
                    {subjects.map(sub => (
                      <option key={sub} value={sub}>{sub}</option>
                    ))}
                  </select>
                  {errors.subject && (
                    <p style={{ color: '#f44336', fontSize: '12px', marginTop: '5px' }}>
                      {errors.subject}
                    </p>
                  )}
                </div>
              </div>
            )}
          </div>

          {/* Footer Buttons */}
          <div style={{
            padding: '20px 30px',
            borderTop: '1px solid #e0e0e0',
            display: 'flex',
            justifyContent: 'space-between',
            background: '#f8f9fa'
          }}>
            <button
              type="button"
              onClick={onClose}
              style={{
                padding: '10px 20px',
                background: 'transparent',
                border: '2px solid #e0e0e0',
                borderRadius: '8px',
                cursor: 'pointer',
                fontSize: '14px',
                fontWeight: 'bold',
                color: '#666'
              }}
            >
              Cancel
            </button>

            <div>
              {step === 2 && (
                <button
                  type="button"
                  onClick={handleBack}
                  style={{
                    padding: '10px 20px',
                    marginRight: '10px',
                    background: 'transparent',
                    border: '2px solid #4facfe',
                    borderRadius: '8px',
                    cursor: 'pointer',
                    fontSize: '14px',
                    fontWeight: 'bold',
                    color: '#4facfe'
                  }}
                >
                  ← Back
                </button>
              )}

              {step === 1 ? (
                <button
                  type="button"
                  onClick={handleNext}
                  style={{
                    padding: '10px 30px',
                    background: 'linear-gradient(135deg, #667eea, #764ba2)',
                    color: 'white',
                    border: 'none',
                    borderRadius: '8px',
                    cursor: 'pointer',
                    fontSize: '14px',
                    fontWeight: 'bold'
                  }}
                >
                  Next →
                </button>
              ) : (
                <button
                  type="submit"
                  style={{
                    padding: '10px 30px',
                    background: 'linear-gradient(135deg, #43e97b, #38f9d7)',
                    color: 'white',
                    border: 'none',
                    borderRadius: '8px',
                    cursor: 'pointer',
                    fontSize: '14px',
                    fontWeight: 'bold'
                  }}
                >
                  ✓ Create User
                </button>
              )}
            </div>
          </div>
        </form>
      </div>
    </div>
  );
}

export default AddUserForm;
